class Solution:
    def countMatchingSubarrays(self, nums, pattern):
        def sgn(a, b):
            if b > a:
                return 1
            if b == a:
                return 0
            return -1
        n = len(nums)
        m = len(pattern)
        count = 0
        for i in range(n - m):
            ok = True
            for k in range(m):
                if sgn(nums[i + k], nums[i + k + 1]) != pattern[k]:
                    ok = False
                    break
            if ok:
                count += 1
        return count

