class Solution:
    def countMatchingSubarrays(self, nums, pattern):
        n = len(nums)
        signs = []
        for i in range(n - 1):
            if nums[i + 1] > nums[i]:
                signs.append(1)
            elif nums[i + 1] == nums[i]:
                signs.append(0)
            else:
                signs.append(-1)
        m = len(pattern)
        count = 0
        for i in range(len(signs) - m + 1):
            if signs[i:i + m] == pattern:
                count += 1
        return count

