var countMatchingSubarrays = function(nums, pattern) {
    const n = nums.length;
    const signs = [];
    for (let i = 0; i < n - 1; i++) {
        if (nums[i + 1] > nums[i]) signs.push(1);
        else if (nums[i + 1] === nums[i]) signs.push(0);
        else signs.push(-1);
    }
    const m = pattern.length;
    let count = 0;
    for (let i = 0; i + m <= signs.length; i++) {
        let ok = true;
        for (let k = 0; k < m; k++) {
            if (signs[i + k] !== pattern[k]) { ok = false; break; }
        }
        if (ok) count++;
    }
    return count;
};
